"use-client"
import { useState } from "react";
import { Star } from "lucide-react"; // Import only the Star icon

interface StarRatingProps {
  value: number;
  onChange: (rating: number) => void;
  maxRating?: number;
  size?: string;
}

export const StarRating: React.FC<StarRatingProps> = ({
  value,
  onChange,
  maxRating = 5,
  size = "w-5 h-5",
}) => {
  const [hoverRating, setHoverRating] = useState(value);
  const currentRating = value || 0; // 🔄 Fallback to 0 if value is undefined

  const handleStarClick = (rating: number) => {
    onChange(rating);
  };

  const handleMouseEnter = (rating: number) => {
    setHoverRating(rating);
  };

  const handleMouseLeave = () => {
    setHoverRating(value);
  };

  return (
    <div className="flex items-center space-x-2">
      {[...Array(maxRating).keys()].map((index) => {
        const rating = index + 1;
        const isFilled = rating <= (hoverRating || value);
        return (
          <button
            key={rating}
            type="button"
            className="focus:outline-none"
            onClick={() => handleStarClick(rating)}
            onMouseEnter={() => handleMouseEnter(rating)}
            onMouseLeave={handleMouseLeave}
            aria-label={`Rate ${rating} stars`}
          >
            <Star
              className={`${size} ${
                isFilled ? "fill-yellow-400 text-yellow-400" : "text-gray-300"
              }`}
            />
          </button>
        );
      })}
    </div>
  );
};